import { initTRPC } from "@trpc/server";
import superjson from "superjson";
import { z } from "zod";

/**
 * Initialization of tRPC backend.
 *
 * Should be done only once per backend.
 */
const t = initTRPC.create({
  transformer: superjson,
});

/**
 * Export reusable router and procedure helpers
 * that can be used throughout the router.
 */
export const router = t.router;
export const publicProcedure = t.procedure;

/**
 * App router definition.
 *
 * Defines the `addMessage` mutation which accepts a string `text`
 * and returns `{ success: true, message: text }`.
 */
export const appRouter = router({
  addMessage: publicProcedure
    .input(z.object({ text: z.string() }))
    .mutation(async ({ input }) => {
      return {
        success: true as const,
        message: input.text,
      };
    }),
});

/**
 * Export the caller factory from the tRPC instance.
 * In tRPC v11, `createCallerFactory` is accessed via `t.createCallerFactory`,
 * not as a direct import from `@trpc/server`.
 */
export const createCallerFactory = t.createCallerFactory;

/**
 * Export type definition of the API.
 */
export type AppRouter = typeof appRouter;

import { appRouter, createCallerFactory } from "@/server/trpc";

/**
 * Create a server-side caller for the app router.
 *
 * Uses `createCallerFactory` from the tRPC instance to create
 * a caller that can invoke procedures directly from the server
 * (e.g., in Server Actions) without going over HTTP.
 */
const createCaller = createCallerFactory(appRouter);

export { createCaller };

"use server";

import { createCaller } from "@/server/caller";

/**
 * Server Action that calls the `addMessage` mutation via the tRPC caller.
 *
 * This is a "use server" function, meaning it runs exclusively on the server.
 * It uses `createCallerFactory` to create a caller that invokes the tRPC
 * procedure directly without going over HTTP.
 */
export async function addMessageAction(text: string) {
  const caller = createCaller({});
  const result = await caller.addMessage({ text });
  return result;
}

"use client";

import { useState, useTransition } from "react";
import { addMessageAction } from "@/app/actions";

export function MessageForm() {
  const [message, setMessage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isPending, startTransition] = useTransition();

  function handleSubmit(formData: FormData) {
    const text = formData.get("text") as string;

    if (!text || !text.trim()) {
      setError("Please enter a message.");
      setMessage(null);
      return;
    }

    setError(null);

    startTransition(async () => {
      try {
        const result = await addMessageAction(text);
        setMessage(result.message);
      } catch (err) {
        setError(
          err instanceof Error ? err.message : "An unexpected error occurred."
        );
        setMessage(null);
      }
    });
  }

  return (
    <div className="flex flex-col gap-6 w-full max-w-md">
      <form
        action={handleSubmit}
        className="flex flex-col gap-4"
      >
        <div className="flex flex-col gap-2">
          <label
            htmlFor="text"
            className="text-sm font-medium text-zinc-700 dark:text-zinc-300"
          >
            Message
          </label>
          <input
            id="text"
            name="text"
            type="text"
            placeholder="Type your message..."
            className="h-10 rounded-md border border-zinc-300 dark:border-zinc-700 bg-white dark:bg-zinc-900 px-3 text-sm text-zinc-900 dark:text-zinc-100 placeholder:text-zinc-400 focus:outline-none focus:ring-2 focus:ring-zinc-950 dark:focus:ring-zinc-300"
            disabled={isPending}
          />
        </div>

        <button
          type="submit"
          disabled={isPending}
          className="flex h-10 items-center justify-center rounded-md bg-zinc-900 px-4 text-sm font-medium text-white transition-colors hover:bg-zinc-800 disabled:opacity-50 dark:bg-zinc-100 dark:text-zinc-900 dark:hover:bg-zinc-200"
        >
          {isPending ? "Sending..." : "Send Message"}
        </button>
      </form>

      {message && (
        <div className="rounded-md border border-green-200 dark:border-green-800 bg-green-50 dark:bg-green-950 p-4">
          <p className="text-sm font-medium text-green-800 dark:text-green-200">
            Success!
          </p>
          <p className="text-sm text-green-700 dark:text-green-300 mt-1">
            {message}
          </p>
        </div>
      )}

      {error && (
        <div className="rounded-md border border-red-200 dark:border-red-800 bg-red-50 dark:bg-red-950 p-4">
          <p className="text-sm font-medium text-red-800 dark:text-red-200">
            Error
          </p>
          <p className="text-sm text-red-700 dark:text-red-300 mt-1">
            {error}
          </p>
        </div>
      )}
    </div>
  );
}

import { MessageForm } from "@/app/MessageForm";

export default function Home() {
  return (
    <div className="flex flex-col flex-1 items-center justify-center bg-zinc-50 dark:bg-black px-4">
      <main className="flex w-full max-w-3xl flex-col items-center gap-8 py-32">
        <div className="flex flex-col items-center gap-3 text-center">
          <h1 className="text-3xl font-semibold leading-10 tracking-tight text-black dark:text-zinc-50">
            tRPC + Next.js Server Actions
          </h1>
          <p className="max-w-md text-lg leading-8 text-zinc-600 dark:text-zinc-400">
            Enter a message below. It will be sent via a Server Action that
            calls a tRPC mutation on the server.
          </p>
        </div>

        <MessageForm />
      </main>
    </div>
  );
}
